"use client";

import React, { useState, useEffect, useRef } from "react";
import { useRouter } from "next/navigation";

interface MockBookmark {
  title: string;
  url: string;
  tag: string;
}

export const LandingPageClient: React.FC<{ isLoggedIn?: boolean, userEmail?: string, userName?: string }> = ({ isLoggedIn, userEmail, userName }) => {
  const router = useRouter();

  // Loader states
  const [isLoading, setIsLoading] = useState(true);
  const [loaderExiting, setLoaderExiting] = useState(false);
  const [loadProgress, setLoadProgress] = useState(0);
  const [loaderPhase, setLoaderPhase] = useState(0); // 0=brand, 1=status, 2=ready
  const [statusIndex, setStatusIndex] = useState(0);
  const LOADER_STATUS_LINES = [
    "01 // SECURING ENVIRONMENT",
    "02 // RETRIEVING DIGITAL MEMORIES",
    "03 // CALIBRATING KNOWLEDGE INDEX",
    "04 // RENDERING INTERFACE",
  ];

  // Transition exit state
  const [isExiting, setIsExiting] = useState(false);

  // Mobile Menu state
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // Profile Dropdown state
  const [isProfileDropdownOpen, setIsProfileDropdownOpen] = useState(false);

  // Scroll reveal states
  const [workflowRevealed, setWorkflowRevealed] = useState(false);
  const [statsRevealed, setStatsRevealed] = useState(false);
  const [featuresRevealed, setFeaturesRevealed] = useState(false);

  // Stats visibility state
  const [statsVisible, setStatsVisible] = useState(false);
  const [bookmarksCount, setBookmarksCount] = useState(0);
  const [speedCount, setSpeedCount] = useState(100);
  const [teamsCount, setTeamsCount] = useState(0);

  // Workflow simulator state
  const [activeStep, setActiveStep] = useState<number>(1);
  const [simStep2Tags, setSimStep2Tags] = useState<string[]>([]);

  // Feature Playgrounds state
  const [searchQuery, setSearchQuery] = useState("");
  const [tagInput, setTagInput] = useState("");
  const [detectedTags, setDetectedTags] = useState<string[]>([]);
  const [collabHovered, setCollabHovered] = useState(false);
  const [collabLogs, setCollabLogs] = useState<string[]>(["Workspace initialized."]);

  // Mock search bookmark data
  const MOCK_SEARCH_DATA: MockBookmark[] = [
    { title: "Next.js 16 Routing Guide", url: "nextjs.org/docs", tag: "dev" },
    { title: "Sleek Glassmorphism Effects", url: "glassy.ui/styles", tag: "design" },
    { title: "Introduction to Agentic AI", url: "deepmind.google/ai", tag: "ai" },
    { title: "Advanced CSS Variables", url: "css-tricks.com/vars", tag: "design" },
  ];

  // Phased loader orchestration
  useEffect(() => {
    // Phase 0: Brand reveal (first 400ms handled by CSS animation delays)
    const phaseTimer1 = setTimeout(() => setLoaderPhase(1), 500);

    // Phase 1: Progress bar + cycling status text
    const progressInterval = setInterval(() => {
      setLoadProgress((prev) => {
        if (prev >= 100) {
          clearInterval(progressInterval);
          return 100;
        }
        // Ease-out curve: fast start, slow finish
        const remaining = 100 - prev;
        const step = Math.max(0.5, remaining * 0.06);
        return Math.min(100, prev + step);
      });
    }, 20);

    // Cycle status text every 450ms
    const statusInterval = setInterval(() => {
      setStatusIndex((prev) => {
        if (prev >= 3) {
          clearInterval(statusInterval);
          return 3;
        }
        return prev + 1;
      });
    }, 450);

    // Phase 2: Ready state
    const phaseTimer2 = setTimeout(() => {
      setLoaderPhase(2);
      setLoadProgress(100);
    }, 2200);

    // Exit: curtain-up animation, then hide
    const exitTimer = setTimeout(() => {
      setLoaderExiting(true);
      setTimeout(() => setIsLoading(false), 800);
    }, 2800);

    return () => {
      clearTimeout(phaseTimer1);
      clearInterval(progressInterval);
      clearInterval(statusInterval);
      clearTimeout(phaseTimer2);
